// Extrair códigos de funcionários do HTML
const input = $input.first().json;
let htmlContent;

try {
  const rawHtml = input.xml_ref || '';
  const cdataMatch = rawHtml.match(/<!\[CDATA\[(.*?)\]\]>/s);

  if (!cdataMatch) {
    throw new Error('Dados CDATA não encontrados');
  }

  htmlContent = cdataMatch[1].trim();
} catch (error) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'employers_plus',
    event: 'validation_error',
    message: error.message,
    level: 'error'
  }));
  return {
    statusCode: 400,
    body: { ok: false, error: 'Dados HTML inválidos', details: error.message }
  };
}

// Parse do HTML para extrair códigos
const rowPattern = /<tr[^>]*class="table-row-body"[^>]*codigo="([^"]+)"[^>]*>/g;
const extracted = [];
let match;

while ((match = rowPattern.exec(htmlContent)) !== null) {
  const codigo = match[1];
  if (codigo) {
    extracted.push({ codigo });
  }
}

if (extracted.length === 0) {
  console.log(JSON.stringify({
    timestamp: new Date().toISOString(),
    route: 'employers_plus',
    event: 'no_data_extracted',
    level: 'warning'
  }));
  return {
    statusCode: 400,
    body: { ok: false, error: 'Nenhum código de funcionário encontrado' }
  };
}

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'employers_plus',
  event: 'codes_extracted',
  count: extracted.length,
  level: 'info'
}));

return {
  statusCode: 200,
  body: {
    message: 'Employee codes extracted successfully.',
    ids: extracted
  }
};
